#include <stdio.h>

int main() {
    int t, x;
    scanf("%d", &t);
    while (t--) {
        scanf("%d", &x);
        if (x % 10 == 0) {
            printf("0\n");
        } else if (x % 5 == 0) {
            printf("1\n");
        } else {
            printf("-1\n");
        }
    }
    return 0;
}

