import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();

        while (t-- > 0) {
            int x = sc.nextInt();
            if (x % 10 == 0) {
                System.out.println(0);
            } else if (x % 5 == 0) {
                System.out.println(1);
            } else {
                System.out.println(-1);
            }
        }

    }
}

